import{c as a,Q as e,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"The Anatomy of an Agent Harness","description":"","frontmatter":{"title":"The Anatomy of an Agent Harness","authors":"Daily Dose of DS（Avi Chawla）","source":"https://blog.dailydoseofds.com/p/the-anatomy-of-an-agent-harness","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2026-daily-dose-ds-anatomy-agent-harness.md","filePath":"research/agent-harness/references/2026-daily-dose-ds-anatomy-agent-harness.md","lastUpdated":1779894392000}'),o={name:"research/agent-harness/references/2026-daily-dose-ds-anatomy-agent-harness.md"};function s(d,t,i,l,h,g){return e(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="the-anatomy-of-an-agent-harness" tabindex="-1">The Anatomy of an Agent Harness <a class="header-anchor" href="#the-anatomy-of-an-agent-harness" aria-label="Permalink to &quot;The Anatomy of an Agent Harness&quot;">​</a></h1><ul><li><strong>作者</strong>: Daily Dose of DS（Avi Chawla）</li><li><strong>平台</strong>: Substack</li><li><strong>URL</strong>: <a href="https://blog.dailydoseofds.com/p/the-anatomy-of-an-agent-harness" target="_blank" rel="noreferrer">https://blog.dailydoseofds.com/p/the-anatomy-of-an-agent-harness</a></li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority B — 目前最完整的 harness 組件分解（11 個生產級組件）</li></ul><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><p>模型不是瓶頸。<strong>Harness 就是產品</strong>，決定了同一底層模型的野生性能差異。</p><p>驗證案例：LangChain 只改變基礎設施（不改模型）就從 TerminalBench 2.0 外賽區升至第 5 名。</p><hr><h2 id="_11-個生產級-harness-組件" tabindex="-1">11 個生產級 Harness 組件 <a class="header-anchor" href="#_11-個生產級-harness-組件" aria-label="Permalink to &quot;11 個生產級 Harness 組件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>組件</th><th>核心功能</th></tr></thead><tbody><tr><td>1</td><td><strong>Orchestration Loop</strong></td><td>Thought-Action-Observation 週期；系統的心跳</td></tr><tr><td>2</td><td><strong>Tools</strong></td><td>帶名稱、描述、參數類型的 schema；執行、驗證、結果格式化</td></tr><tr><td>3</td><td><strong>Memory</strong></td><td>短期（對話歷史）+ 長期（跨 session 檔案/資料庫）</td></tr><tr><td>4</td><td><strong>Context Management</strong></td><td>Context rot 對策：壓縮、觀察 masking、即時檢索、子 agent 委派</td></tr><tr><td>5</td><td><strong>Prompt Construction</strong></td><td>系統提示 → 工具定義 → 記憶檔案 → 對話歷史的組裝順序</td></tr><tr><td>6</td><td><strong>Output Parsing</strong></td><td>原生工具呼叫回傳結構化物件，避免自由文本解析</td></tr><tr><td>7</td><td><strong>State Management</strong></td><td>類型化字典追蹤進度；邊界檢查點支援恢復</td></tr><tr><td>8</td><td><strong>Error Handling</strong></td><td>四種錯誤類型：暫時性、LLM 可恢復、用戶可修正、意外性</td></tr><tr><td>9</td><td><strong>Guardrails &amp; Safety</strong></td><td>三層：輸入層 / 輸出層 / 工具層</td></tr><tr><td>10</td><td><strong>Verification Loops</strong></td><td>規則型 / 視覺型 / LLM-as-judge（能提升 2-3 倍品質）</td></tr><tr><td>11</td><td><strong>Subagent Orchestration</strong></td><td>專門 agent 處理邊界子任務或完整交接</td></tr></tbody></table><hr><h2 id="_7-項關鍵設計決策" tabindex="-1">7 項關鍵設計決策 <a class="header-anchor" href="#_7-項關鍵設計決策" aria-label="Permalink to &quot;7 項關鍵設計決策&quot;">​</a></h2><ol><li><strong>單 vs 多 agent</strong>: 是否需要多個專門 agent 協作？</li><li><strong>ReAct vs Plan-Execute</strong>: 推理-行動交錯還是先規劃後執行？</li><li><strong>Context 管理策略</strong>: 壓縮、掩蓋、還是委派？</li><li><strong>驗證設計</strong>: 哪種 verification loop 適合這個任務？</li><li><strong>權限架構</strong>: 哪些行動需要人工審批？</li><li><strong>工具範圍</strong>: 哪些工具應該暴露，哪些不應該？</li><li><strong>Harness 厚度</strong>: 多少複雜度是必要的，多少是過度設計？</li></ol><hr><h2 id="component-執行循環" tabindex="-1">Component 執行循環 <a class="header-anchor" href="#component-執行循環" aria-label="Permalink to &quot;Component 執行循環&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Context 組裝 → LLM 推理 → 輸出分類 → 工具執行 → 結果包裝 → Context 更新 → 迴圈</span></span></code></pre></div><hr><h2 id="scaffolding-原則" tabindex="-1">Scaffolding 原則 <a class="header-anchor" href="#scaffolding-原則" aria-label="Permalink to &quot;Scaffolding 原則&quot;">​</a></h2><p>隨著模型進步，harness 複雜性應<strong>下降</strong>。好的 harness 是臨時基礎設施：</p><ul><li>V1 Harness: 需要大量輔助（早停、錯誤處理、多次重試）</li><li>Future Harness: 模型本身具備這些能力，harness 變薄</li></ul><hr><h2 id="核心洞見" tabindex="-1">核心洞見 <a class="header-anchor" href="#核心洞見" aria-label="Permalink to &quot;核心洞見&quot;">​</a></h2><ul><li>Verification 能使品質提升 <strong>2-3 倍</strong>（三種驗證方式各有適用場景）</li><li>Error Handling 要分類四種類型，而非統一處理</li><li>Context Management 是 11 個組件中最被低估的</li><li>Subagent Orchestration 是 Context Firewall 的實現方式</li></ul><hr><h2 id="與本-workspace-的對應" tabindex="-1">與本 Workspace 的對應 <a class="header-anchor" href="#與本-workspace-的對應" aria-label="Permalink to &quot;與本 Workspace 的對應&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Anatomy 組件</th><th>Workspace 的實現</th></tr></thead><tbody><tr><td>Orchestration Loop</td><td>agentic loop + Claude 核心能力</td></tr><tr><td>Tools</td><td>Bash/Read/Edit/Write + MCP tools</td></tr><tr><td>Memory</td><td>Auto Memory + context-management.md</td></tr><tr><td>Context Management</td><td>/compact + subagent 委派規則</td></tr><tr><td>Prompt Construction</td><td>CLAUDE.md 分層載入（常駐/按需/手動）</td></tr><tr><td>Output Parsing</td><td>結構化回傳（TodoWrite、JSON output）</td></tr><tr><td>State Management</td><td>ACTIVE_TASK.md + TodoWrite</td></tr><tr><td>Error Handling</td><td>core.md 驗證規則 + healthcheck.sh</td></tr><tr><td>Guardrails &amp; Safety</td><td>security-hygiene.md + PreToolUse hook</td></tr><tr><td>Verification Loops</td><td>/deep-review skill + healthcheck.sh</td></tr><tr><td>Subagent Orchestration</td><td>subagent-strategy.md</td></tr></tbody></table>',25)])])}const p=a(o,[["render",s]]);export{m as __pageData,p as default};
